const dashData = $('Fetch Dashboard Data').item.json;
const leads = $('Fetch Voice Leads').all().map(i => i.json);

const ig = dashData.instagram || {};
const fb = dashData.facebook || {};

const newLeads = leads.filter(l => l.status === 'New').length;
const contactedLeads = leads.filter(l => l.status === 'Contacted').length;
const bookedLeads = leads.filter(l => l.status === 'Booked').length;
const totalLeads = leads.length;

const summary = `TRIBAL COWBOY DAILY BRIEF — ${new Date().toLocaleDateString('en-US', {weekday:'long', year:'numeric', month:'long', day:'numeric'})}

📸 INSTAGRAM
  Followers: ${ig.followers || 'N/A'}
  Reach: ${ig.reach || 'N/A'}
  Impressions: ${ig.impressions || 'N/A'}
  Profile Views: ${ig.profile_views || 'N/A'}
  Last Updated: ${ig.last_updated ? new Date(ig.last_updated).toLocaleString() : 'N/A'}

👍 FACEBOOK
  Followers: ${fb.followers || 'N/A'}
  Reach: ${fb.reach || 'N/A'}
  Engagement: ${fb.engagement || 'N/A'}
  Last Updated: ${fb.last_updated ? new Date(fb.last_updated).toLocaleString() : 'N/A'}

📞 VOICE LEADS PIPELINE
  Total Leads: ${totalLeads}
  New (need follow-up): ${newLeads}
  Contacted: ${contactedLeads}
  Booked: ${bookedLeads}

${newLeads > 0 ? '⚠️  ACTION NEEDED: ' + newLeads + ' new lead(s) need follow-up today!' : '✅ All leads have been contacted.'}

---
Latest Leads:
${leads.slice(0, 5).map(l => `  • ${l.caller_name || 'Unknown'} — ${l.service_requested || 'Service TBD'} — ${l.event_date || 'Date TBD'} — Status: ${l.status || 'New'}`).join('\n')}`;

return [{ json: { summary, newLeads, totalLeads, bookedLeads } }];
